1131: /* disable interrupts */
1132: static void azx_int_disable(struct azx *chip)
1133: {
1134: 	int i;
1135: 
1136: 	/* disable interrupts in stream descriptor */
1137: 	for (i = 0; i < chip->num_streams; i++) {
1138: 		struct azx_dev *azx_dev = &chip->azx_dev[i];
1139: 		azx_sd_writeb(azx_dev, SD_CTL,
1140: 			      azx_sd_readb(azx_dev, SD_CTL) & ~SD_INT_MASK);
1141: 	}
1142: 
1143: 	/* disable SIE for all streams */
1144: 	azx_writeb(chip, INTCTL, 0);
1145: 
1146: 	/* disable controller CIE and GIE */
1147: 	azx_writel(chip, INTCTL, azx_readl(chip, INTCTL) &
1148: 		   ~(ICH6_INT_CTRL_EN | ICH6_INT_GLOBAL_EN));
1149: }
