1152: static void azx_int_clear(struct azx *chip)
1153: {
1154: 	int i;
1155: 
1156: 	/* clear stream status */
1157: 	for (i = 0; i < chip->num_streams; i++) {
1158: 		struct azx_dev *azx_dev = &chip->azx_dev[i];
1159: 		azx_sd_writeb(azx_dev, SD_STS, SD_INT_MASK);
1160: 	}
1161: 
1162: 	/* clear STATESTS */
1163: 	azx_writeb(chip, STATESTS, STATESTS_INT_MASK);
1164: 
1165: 	/* clear rirb status */
1166: 	azx_writeb(chip, RIRBSTS, RIRB_INT_MASK);
1167: 
1168: 	/* clear int status */
1169: 	azx_writel(chip, INTSTS, ICH6_INT_CTRL_EN | ICH6_INT_ALL_STREAM);
1170: }
