{"content":"2513: static int azx_suspend(struct device *dev)
2514: {
2515: 	struct pci_dev *pci = to_pci_dev(dev);
2516: 	struct snd_card *card = dev_get_drvdata(dev);
2517: 	struct azx *chip = card->private_data;
2518: 	struct azx_pcm *p;
2519: 
2520: 	snd_power_change_state(card, SNDRV_CTL_POWER_D3hot);
2521: 	azx_clear_irq_pending(chip);
2522: 	list_for_each_entry(p, &chip->pcm_list, list)
2523: 		snd_pcm_suspend_all(p->pcm);
2524: 	if (chip->initialized)
2525: 		snd_hda_suspend(chip->bus);
2526: 	azx_stop_chip(chip);
2527: 	if (chip->irq >= 0) {
2528: 		free_irq(chip->irq, chip);
2529: 		chip->irq = -1;
2530: 	}
2531: 	if (chip->msi)
2532: 		pci_disable_msi(chip->pci);
2533: 	pci_disable_device(pci);
2534: 	pci_save_state(pci);
2535: 	pci_set_power_state(pci, PCI_D3hot);
2536: 	return 0;
2537: }
