2539: static int azx_resume(struct device *dev)
2540: {
2541: 	struct pci_dev *pci = to_pci_dev(dev);
2542: 	struct snd_card *card = dev_get_drvdata(dev);
2543: 	struct azx *chip = card->private_data;
2544: 
2545: 	pci_set_power_state(pci, PCI_D0);
2546: 	pci_restore_state(pci);
2547: 	if (pci_enable_device(pci) < 0) {
2548: 		printk(KERN_ERR "hda-intel: pci_enable_device failed, "
2549: 		       "disabling device\n");
2550: 		snd_card_disconnect(card);
2551: 		return -EIO;
2552: 	}
2553: 	pci_set_master(pci);
2554: 	if (chip->msi)
2555: 		if (pci_enable_msi(pci) < 0)
2556: 			chip->msi = 0;
2557: 	if (azx_acquire_irq(chip, 1) < 0)
2558: 		return -EIO;
2559: 	azx_init_pci(chip);
2560: 
2561: 	azx_init_chip(chip, 1);
2562: 
2563: 	snd_hda_resume(chip->bus);
2564: 	snd_power_change_state(card, SNDRV_CTL_POWER_D0);
